def minPath(grid, k):
    n = len(grid)

    # Find position of each value
    pos = {}
    for i in range(n):
        for j in range(n):
            pos[grid[i][j]] = (i, j)

    # For each cell, find its neighbors' minimum value
    def get_neighbors(r, c):
        neighbors = []
        for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
            nr, nc = r+dr, c+dc
            if 0 <= nr < n and 0 <= nc < n:
                neighbors.append(grid[nr][nc])
        return neighbors

    # BFS/dynamic programming approach
    # State: current cell, steps taken
    # We want minimum lexicographic path of length k

    # Use greedy: at each step, from current set of positions,
    # pick the minimum value reachable

    # Start: we can be at any cell
    # current_positions = all cells

    # At each step, we track the set of (cell) positions that lead to
    # the current minimum path prefix

    # Initialize: find minimum value in grid = 1
    # But we need to be greedy about lexicographic order

    # current_states = set of positions we could currently be at
    # that all have the same (minimum) path prefix so far

    # Step 1: find minimum first value
    min_val = min(grid[i][j] for i in range(n) for j in range(n))

    # All positions with that minimum value (should be one since 1..N*N each appears once)
    current_positions = set()
    for i in range(n):
        for j in range(n):
            if grid[i][j] == min_val:
                current_positions.add((i,j))

    result = [min_val]

    for step in range(k-1):
        # Find all reachable neighbors from current positions
        # Pick the minimum value neighbor
        min_neighbor = None
        for (r, c) in current_positions:
            for val in get_neighbors(r, c):
                if min_neighbor is None or val < min_neighbor:
                    min_neighbor = val

        result.append(min_neighbor)

        # Update current positions: all neighbors with min_neighbor value
        # from any position in current_positions
        new_positions = set()
        for (r, c) in current_positions:
            for dr, dc in [(-1,0),(1,0),(0,-1),(0,1)]:
                nr, nc = r+dr, c+dc
                if 0 <= nr < n and 0 <= nc < n:
                    if grid[nr][nc] == min_neighbor:
                        new_positions.add((nr, nc))

        current_positions = new_positions

    return result

